  ('medical-tech-moex-21114', 'medical-tech', 'medical-tech-moex-093-5c00801d', 'sub-medical-tech-13', NULL, 'single_choice', '下列有關滑膜液中乳酸濃度的敘述，何者正確？ 濃度超過10倍正常濃度時，與敗血症關節炎有關  濃度中等上升時，可以排除感染 淋菌性關節炎時，濃度會上升  類風濕性關節炎時，濃度不會上升', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:17+00:00", "source_pdf_sha1": "c9542f67b3c1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床鏡檢學(包括寄生蟲學)", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
