  ('medical-tech-moex-21116', 'medical-tech', 'medical-tech-moex-093-5c00801d', 'sub-medical-tech-13', NULL, 'single_choice', '下列有關Charcot-Leyden晶體的敘述，何者正確？ 為嗜中性白血球分解後的產物 新鮮的檢體較放置一段時間後的檢體，更容易見到此結晶 腹膜液中若嗜中性白血球大量上升，則有可能見到此結晶 通常出現在支氣管氣喘病人的痰液中', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:17+00:00", "source_pdf_sha1": "c9542f67b3c1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床鏡檢學(包括寄生蟲學)", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 42, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
